const categories = [
  {
    id: 1,
    name: 'Fruits',
    items: [
      { id: 11, name: 'Apple' },
      { id: 12, name: 'Banana' },
    ],
  },
  {
    id: 2,
    name: 'Vegetables',
    items: [
      { id: 21, name: 'Carrot' },
      { id: 22, name: 'Broccoli' },
    ],
  },
];

function GroceryList({ categories }) {
  return (
    <ul>
      {categories.map(cat => (
        <li key={cat.id}>
          <strong>{cat.name}</strong>
          <ul>
            {cat.items.map(item => (
              <li key={item.id}>{item.name}</li>
            ))}
          </ul>
        </li>
      ))}
    </ul>
  );
}

function ItemList({ items }) {
  return (
    <ul>
      {items.map(item => (
        <li key={item.id}>{item.name}</li>
      ))}
    </ul>
  );
}

function CategoryList({ categories }) {
  return (
    <ul>
      {categories.map(cat => (
        <li key={cat.id}>
          <strong>{cat.name}</strong>
          <ItemList items={cat.items} />
        </li>
      ))}
    </ul>
  );
}

// Group an array by a key field
function groupBy(arr, key) {
  return arr.reduce((acc, item) => {
    const group = item[key];
    if (!acc[group]) acc[group] = [];
    acc[group].push(item);
    return acc;
  }, {});
}

const contacts = [
  { id: 1, name: 'Alice', dept: 'Engineering' },
  { id: 2, name: 'Bob',   dept: 'Design' },
  { id: 3, name: 'Carol', dept: 'Engineering' },
  { id: 4, name: 'Dave',  dept: 'Design' },
];

function GroupedContacts({ contacts }) {
  const groups = groupBy(contacts, 'dept'); // { Engineering: [...], Design: [...] }

  return (
    <div>
      {Object.entries(groups).map(([dept, people]) => (
        <section key={dept}>
          <h3>{dept}</h3>
          <ul>
            {people.map(p => (
              <li key={p.id}>{p.name}</li>
            ))}
          </ul>
        </section>
      ))}
    </div>
  );
}

// Data: Subjects -> Chapters -> Lessons
function LessonItem({ lesson }) {
  return <li key={lesson.id}>{lesson.title}</li>;
}

function ChapterSection({ chapter }) {
  return (
    <li key={chapter.id}>
      <h4>{chapter.title}</h4>
      <ul>
        {chapter.lessons.map(l => (
          <LessonItem key={l.id} lesson={l} />
        ))}
      </ul>
    </li>
  );
}

function SubjectOutline({ subjects }) {
  return (
    <div>
      {subjects.map(subject => (
        <section key={subject.id}>
          <h3>{subject.title}</h3>
          <ul>
            {subject.chapters.map(ch => (
              <ChapterSection key={ch.id} chapter={ch} />
            ))}
          </ul>
        </section>
      ))}
    </div>
  );
}

// Tree node shape: { id, name, children?: TreeNode[] }
function TreeNode({ node }) {
  return (
    <li>
      {node.name}
      {node.children && node.children.length > 0 && (
        <ul>
          {node.children.map(child => (
            <TreeNode key={child.id} node={child} />
          ))}
        </ul>
      )}
    </li>
  );
}

function FileTree({ roots }) {
  return (
    <ul>
      {roots.map(node => (
        <TreeNode key={node.id} node={node} />
      ))}
    </ul>
  );
}

function TaskBoard({ tasks }) {
  const STATUS_ORDER = ['todo', 'in-progress', 'done'];

  const grouped = STATUS_ORDER.reduce((acc, status) => {
    acc[status] = tasks.filter(t => t.status === status);
    return acc;
  }, {});

  return (
    <div style={{ display: 'flex', gap: '1rem' }}>
      {STATUS_ORDER.map(status => {
        const column = grouped[status];
        return (
          <section key={status}>
            <h3>
              {status} <span>({column.length})</span>
            </h3>
            <ul>
              {column.map(task => (
                <li key={task.id}>{task.title}</li>
              ))}
            </ul>
          </section>
        );
      })}
    </div>
  );
}

import { useState } from 'react';

function AccordionList({ categories }) {
  const [openIds, setOpenIds] = useState(new Set());

  function toggle(id) {
    setOpenIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  }

  return (
    <ul>
      {categories.map(cat => (
        <li key={cat.id}>
          <button onClick={() => toggle(cat.id)}>
            {cat.name} {openIds.has(cat.id) ? '▲' : '▼'}
          </button>
          {openIds.has(cat.id) && (
            <ul>
              {cat.items.map(item => (
                <li key={item.id}>{item.name}</li>
              ))}
            </ul>
          )}
        </li>
      ))}
    </ul>
  );
}

const NAV = [
  { id: 'home',     label: 'Home',     href: '/' },
  {
    id: 'products', label: 'Products', href: '/products',
    children: [
      { id: 'widgets',  label: 'Widgets',  href: '/products/widgets' },
      { id: 'gadgets',  label: 'Gadgets',  href: '/products/gadgets' },
    ],
  },
  { id: 'about',    label: 'About',    href: '/about' },
];

function NavItem({ item }) {
  return (
    <li>
      <a href={item.href}>{item.label}</a>
      {item.children && (
        <ul>
          {item.children.map(child => (
            <NavItem key={child.id} item={child} />
          ))}
        </ul>
      )}
    </li>
  );
}

function SiteNav() {
  return (
    <nav>
      <ul>
        {NAV.map(item => (
          <NavItem key={item.id} item={item} />
        ))}
      </ul>
    </nav>
  );
}

interface Category {
  id: number;
  name: string;
  items: Item[];
}

interface Item {
  id: number;
  name: string;
}

// Recursive tree node
interface TreeNode {
  id: string;
  label: string;
  children?: TreeNode[]; // self-reference — must use interface, not type alias
}

function CategoryList({ categories }: { categories: Category[] }) {
  return (
    <ul>
      {categories.map(cat => (
        <li key={cat.id}>
          {cat.name}
          <ul>
            {cat.items.map(item => (
              <li key={item.id}>{item.name}</li>
            ))}
          </ul>
        </li>
      ))}
    </ul>
  );
}

import { render, screen } from '@testing-library/react';
import { GroceryList } from './GroceryList';

const CATS = [
  { id: 1, name: 'Fruits',  items: [{ id: 11, name: 'Apple' }, { id: 12, name: 'Banana' }] },
  { id: 2, name: 'Veggies', items: [{ id: 21, name: 'Carrot' }] },
];

test('renders all categories and their items', () => {
  render(<GroceryList categories={CATS} />);

  expect(screen.getByText('Fruits')).toBeInTheDocument();
  expect(screen.getByText('Apple')).toBeInTheDocument();
  expect(screen.getByText('Banana')).toBeInTheDocument();

  expect(screen.getByText('Veggies')).toBeInTheDocument();
  expect(screen.getByText('Carrot')).toBeInTheDocument();
});

test('items are grouped under correct category', () => {
  const { container } = render(<GroceryList categories={CATS} />);
  const [fruitsLi, veggiesLi] = container.querySelectorAll('ul > li');

  expect(fruitsLi.textContent).toContain('Apple');
  expect(fruitsLi.textContent).toContain('Banana');
  expect(fruitsLi.textContent).not.toContain('Carrot');

  expect(veggiesLi.textContent).toContain('Carrot');
  expect(veggiesLi.textContent).not.toContain('Apple');
});
